import{_ as t,o,c as s,ag as n}from"./chunks/framework.ePeAWSvT.js";const a="/assets/deploy.8FPBHqP8.png",r="/assets/deploy-hub-selected.Cy5S944q.png",i="/assets/deploy-hub-selected.Cy5S944q.png",y=JSON.parse('{"title":"Deployments","description":"","frontmatter":{},"headers":[],"relativePath":"guide/deploy.md","filePath":"guide/deploy.md"}'),l={name:"guide/deploy.md"};function d(c,e,p,g,u,h){return o(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="deployments" tabindex="-1">Deployments <a class="header-anchor" href="#deployments" aria-label="Permalink to &quot;Deployments&quot;">​</a></h1><p>The Deployments page manages deploying Data Hub and API Gateway configurations to your environments. Review draft changes and promote configurations to live.</p><p><img src="'+a+'" alt="Deployments Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Data Hub Deployments</strong> — Deploy data hub configurations with publisher and subscriber endpoints</li><li><strong>API Gateway Deployments</strong> — Deploy API gateway configurations with data providers and webhooks</li><li><strong>Version Management</strong> — Track draft and live versions of each configuration</li></ul><h2 id="deploy-a-data-hub" tabindex="-1">Deploy a Data Hub <a class="header-anchor" href="#deploy-a-data-hub" aria-label="Permalink to &quot;Deploy a Data Hub&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>It is highly recommended to include comments every time you release a new version, to document any changes made and provide context between users.</p></div><ol><li>Select <strong>Deploy</strong> from the main menu.</li><li>Select <strong>Data Hubs</strong> from the submenu.</li><li>Select the appropriate <strong>Data Hub</strong> in the left column.</li></ol><p><img src="'+r+'" alt="Deploy Data Hub Selected"></p><p><img src="'+i+'" alt="Deploy Revision Grid"></p><ol start="4"><li>As needed, use the table below to determine next steps.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>You may perform several of the following steps before continuing to deploy. These actions can be taken on versions in any status; however, only available actions will be selectable.</p></div><h3 id="pre-deployment-actions" tabindex="-1">Pre-Deployment Actions <a class="header-anchor" href="#pre-deployment-actions" aria-label="Permalink to &quot;Pre-Deployment Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>Add Comments</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Comments</strong>. Enter text in the <strong>Comments</strong> field, then select <strong>Save</strong>.</td></tr><tr><td><strong>Compare with Live</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Compare with Live</strong>. In the <strong>Compare Configurations</strong> window, view the side-by-side code for any changes and to ensure accuracy. When finished, select <strong>Close</strong>.</td></tr><tr><td><strong>Compare with Previous</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Compare with Previous</strong>. In the <strong>Compare Configurations</strong> window, view the side-by-side code for any changes and to ensure accuracy. When finished, select <strong>Close</strong>.</td></tr><tr><td><strong>View Code</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Code</strong>. View the code to ensure accuracy; when finished, select <strong>Close</strong>.</td></tr></tbody></table><ol start="5"><li>When ready, select <strong>Actions</strong> &gt; <strong>Deploy</strong> in the appropriate row.</li><li>Select <strong>OK</strong> to confirm.</li></ol><div class="warning custom-block"><p class="custom-block-title">Note</p><p>Versions in either Draft or Previously Deployed status can be deployed. Both will supersede the current Live version.</p></div><div class="info custom-block"><p class="custom-block-title">Example</p><p>If a newly deployed Data Hub inadvertently caused issues or didn&#39;t run properly, you can restore a Previously Deployed version to ensure the integration continues to run while you work on repairing the new release.</p></div><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>It is recommended to deploy all data hubs from the <strong>Deploy</strong> &gt; <strong>Data Hubs</strong> tool.</p><p>While it is also possible to deploy from the <strong>Build</strong> &gt; <strong>Data Hubs</strong> &gt; <strong>Actions</strong> &gt; <strong>Deploy</strong> menu, it is strongly advised not to, as it will not provide you the opportunity to perform any of the optional steps previously outlined (e.g. add comments, compare versions, etc.).</p></div><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./versioning.html">Versioning</a> — Manage Data Hub version lifecycle</li><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create and configure Data Hubs</li><li><a href="./test.html">Testing</a> — Verify endpoint behavior before deploying</li><li><a href="./monitor-dashboard.html">Monitor Dashboard</a> — Track deployment health</li></ul>',20)])])}const b=t(l,[["render",d]]);export{y as __pageData,b as default};
